#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M, X;
        scanf("%d %d %d", &N, &M, &X);
        int **mat = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; ++i) {
            mat[i] = (int *)malloc(M * sizeof(int));
            for (int j = 0; j < M; ++j) {
                scanf("%d", &mat[i][j]);
            }
        }
        long long left = 0, right = (long long)N * M - 1;
        int found = 0;
        while (left <= right) {
            long long mid = left + (right - left) / 2;
            int r = mid / M;
            int c = mid % M;
            int val = mat[r][c];
            if (val == X) { found = 1; break; }
            else if (val < X) left = mid + 1;
            else right = mid - 1;
        }
        printf(found ? "YES\n" : "NO\n");
        for (int i = 0; i < N; ++i) free(mat[i]);
        free(mat);
    }
    return 0;
}

