const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let results = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const M = data[idx++];
  const X = data[idx++];
  const matrix = new Array(N);
  for (let i = 0; i < N; i++) {
    matrix[i] = new Array(M);
    for (let j = 0; j < M; j++) {
      matrix[i][j] = data[idx++];
    }
  }
  let left = 0, right = N * M - 1;
  let found = false;
  while (left <= right) {
    const mid = left + Math.floor((right - left) / 2);
    const r = Math.floor(mid / M);
    const c = mid % M;
    const val = matrix[r][c];
    if (val === X) { found = true; break; }
    else if (val < X) left = mid + 1;
    else right = mid - 1;
  }
  results.push(found ? 'YES' : 'NO');
}
